/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[DataEventHandler(tableStr(InventValueReportTmpLine), DataEventType::Inserting)]
public static void InventValueReportTmpLine_onInserting(Common sender, DataEventArgs e)
{
    InventValueReportTmpLine    InventValueReportTmpLineLoc = sender as InventValueReportTmpLine;

    InventJournalTrans inventJournalTrans;

    select * from inventJournalTrans
        where inventJournalTrans.InventTransId == InventValueReportTmpLineLoc.InventTransId
        && InventValueReportTmpLineLoc.InventTransId != '';

    InventValueReportTmpLineLoc.ETG_BatchExpDate = Inventbatch::find(inventDim::find(inventJournalTrans.InventDimId).inventBatchId, InventValueReportTmpLineLoc.ResourceId).expDate;
    InventValueReportTmpLineLoc.ETG_InventDimId = inventJournalTrans.InventDimId;
}
